const src = $input.first().json;
const b = src.body || src;
return [{json:{
  objective: b.objective || b.task || b.chatInput || 'Advance EVEZ system — autonomous wealth accumulation cycle',
  action:    b.action || 'trunk',
  priority:  b.priority || 'high',
  agent_id:  b.agent_id || 'A001',
  source:    b.source || 'webhook',
  ts:        new Date().toISOString()
}}];

const {objective} = $input.first().json;
return [
  {json:{branch:'B1',role:'recon',    prompt:`Research live signals for: ${objective}. List top 3 actionable findings.`}},
  {json:{branch:'B2',role:'skeptic',  prompt:`Stress-test: ${objective}. Return surviving core + 2 rejected assumptions.`}},
  {json:{branch:'B3',role:'architect',prompt:`Refactor into composable structure: ${objective}. Return structure + failure modes.`}},
  {json:{branch:'B4',role:'executor', prompt:`Executable steps for: ${objective}. Return first_action + 3 steps.`}},
].map(b => ({json:{...b, objective, ts: new Date().toISOString()}}));

const items = $input.all();
const branches = items.map(i => {
  const content = i.json.choices?.[0]?.message?.content || JSON.stringify(i.json);
  let parsed = {};
  try { parsed = JSON.parse(content); } catch { parsed = {raw: content.slice(0,200)}; }
  return {branch: i.json.branch || '?', role: i.json.role || '?', ...parsed};
});

// Hash chain entry
let h = 5381;
const s = JSON.stringify(branches);
for(let i=0;i<s.length;i++){h=((h<<5)+h)+s.charCodeAt(i);h|=0;}
const hash = 'sha_' + Math.abs(h).toString(16).padStart(16,'0');

const trunk = {
  trunk_version:     new Date().toISOString(),
  objective:         items[0]?.json?.objective || '?',
  branches_complete: branches.length,
  surviving_logic:   branches.map(b => `[${b.role?.toUpperCase()}] ${b.surviving_core || b.first_action || b.raw || '...'}`).join(' | '),
  key_insight:       branches.find(b => b.role==='executor')?.first_action || branches[0]?.raw?.slice(0,100) || 'processing',
  entry_hash:        hash,
  status:            'ADVANCING',
  n8n_fix:           'Go to Self-Emergent Bus → OpenAI GPT-5 Mini node → Credentials → assign your OpenAI API credential. That single action unblocks all 8 AI agents.',
  next_action:       'POST /webhook/agent-bus-event with action:trunk to trigger next cycle'
};
return [{json: trunk}];

